'use client';

export default function OfflinePage() {
    return (
        <main className="min-h-screen flex items-center justify-center bg-[#F5F0EB] dark:bg-[#1C1C1E] px-4">
            <div className="text-center max-w-sm">
                <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-[#E8E3DC] dark:bg-[#2C2C2E] flex items-center justify-center">
                    <svg viewBox="0 0 24 24" className="w-10 h-10 text-[#C9A96E]" fill="none" stroke="currentColor" strokeWidth={1.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M8.288 15.038a5.25 5.25 0 017.424 0M5.106 11.856c3.807-3.808 9.98-3.808 13.788 0M1.924 8.674c5.565-5.565 14.587-5.565 20.152 0M12.53 18.22l-.53.53-.53-.53a.75.75 0 011.06 0z" />
                    </svg>
                </div>
                <h1
                    className="text-2xl font-bold text-[#1C1C1E] dark:text-[#F5F0EB] mb-2"
                    style={{ fontFamily: 'Playfair Display, Georgia, serif' }}
                >
                    Bağlantı Yok
                </h1>
                <p className="text-[14px] text-[#666] dark:text-[#AEAEB2] mb-6">
                    İnternet bağlantınız yok. Bağlantı sağlandığında sayfa otomatik yenilenecek.
                </p>
                <button
                    onClick={() => window.location.reload()}
                    className="px-6 py-2.5 bg-[#C9A96E] text-white text-[13px] font-semibold hover:bg-[#B8915A] transition-colors"
                >
                    Tekrar Dene
                </button>
            </div>
        </main>
    );
}
